INSERT INTO `payment_method` VALUES (1, '⛆ QRIS', 'Kepompong - Airpay Shopee', '', 'Tinggal Scan ⛆, Masukkan Nominal, dan Bayar!\n\nPastikan angka yang Anda masukkan tepat sesuai nominal di atas agar sistem bisa memverifikasi transaksi Anda secara otomatis.', 'qris', 1);
